        // Parse the XML document
        Document document = parseXmlDocument(xmlResponse);

        // Parse the SAML Response
        SamlResponse samlResponse = parseSamlResponse(document);

        // Validate the response
        validateResponse(samlResponse);

        // Create authenticated session from the first valid assertion
        return createSessionFromResponse(samlResponse);
