    /**
     * Parse XML string into a DOM Document with security settings
     */
    private Document parseXmlDocument(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Security: Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xml));
            return builder.parse(inputSource);
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML response: " + e.getMessage(), e);
        }
    }

    /**
     * Parse the SAML Response element from the Document
     */
    private SamlResponse parseSamlResponse(Document document) throws SamlProcessingException {
        // Find the Response element
        Element responseElement = findResponseElement(document);

        SamlResponse samlResponse = new SamlResponse();

        // Parse Response attributes
        samlResponse.setId(getRequiredAttribute(responseElement, "ID", "Response"));
        samlResponse.setDestination(responseElement.getAttribute("Destination"));
        samlResponse.setInResponseTo(responseElement.getAttribute("InResponseTo"));

        String issueInstantStr = responseElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            samlResponse.setIssueInstant(parseInstant(issueInstantStr));
        }

        // Parse Issuer
        String issuer = getChildElementText(responseElement, SAML2_ASSERTION_NS, "Issuer");
        samlResponse.setIssuer(issuer);

        // Parse Status
        parseStatus(responseElement, samlResponse);

        // Parse Assertions
        NodeList assertionNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        for (int i = 0; i < assertionNodes.getLength(); i++) {
            Element assertionElement = (Element) assertionNodes.item(i);
            SamlAssertion assertion = parseAssertion(assertionElement);
            samlResponse.getAssertions().add(assertion);
        }

        return samlResponse;
    }

    /**
     * Find and validate the Response element in the document
     */
    private Element findResponseElement(Document document) throws SamlProcessingException {
        // Try namespace-aware lookup first
        NodeList responseNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Response");

        if (responseNodes.getLength() == 0) {
            // Fallback: try without namespace
            responseNodes = document.getElementsByTagName("samlp:Response");
        }

        if (responseNodes.getLength() == 0) {
            responseNodes = document.getElementsByTagName("saml2p:Response");
        }

        if (responseNodes.getLength() == 0) {
            // Check if root element is Response
            Element root = document.getDocumentElement();
            if (root != null && "Response".equals(root.getLocalName())) {
                return root;
            }
            throw new SamlProcessingException(
                    "SAML Response element not found. The XML document does not contain a valid SAML Response.");
        }

        if (responseNodes.getLength() > 1) {
            throw new SamlProcessingException(
                    "Multiple Response elements found. A valid SAML response must contain exactly one Response element.");
        }

        return (Element) responseNodes.item(0);
    }

    /**
     * Parse the Status element from the Response
     */
    private void parseStatus(Element responseElement, SamlResponse samlResponse) throws SamlProcessingException {
        NodeList statusNodes = responseElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Status");
        if (statusNodes.getLength() == 0) {
            throw new SamlProcessingException("SAML Response is missing required Status element");
        }

        Element statusElement = (Element) statusNodes.item(0);

        // Get StatusCode
        NodeList statusCodeNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() > 0) {
            Element statusCodeElement = (Element) statusCodeNodes.item(0);
            samlResponse.setStatusCode(statusCodeElement.getAttribute("Value"));
        }

        // Get StatusMessage (optional)
        String statusMessage = getChildElementText(statusElement, SAML2_PROTOCOL_NS, "StatusMessage");
        samlResponse.setStatusMessage(statusMessage);
    }

    /**
     * Parse a SAML Assertion element
     */
    private SamlAssertion parseAssertion(Element assertionElement) throws SamlProcessingException {
        SamlAssertion assertion = new SamlAssertion();

        // Parse assertion attributes
        assertion.setId(getRequiredAttribute(assertionElement, "ID", "Assertion"));

        String issueInstantStr = assertionElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            assertion.setIssueInstant(parseInstant(issueInstantStr));
        }

        // Parse Issuer
        assertion.setIssuer(getChildElementText(assertionElement, SAML2_ASSERTION_NS, "Issuer"));

        // Parse Subject
        parseSubject(assertionElement, assertion);

        // Parse Conditions
        parseConditions(assertionElement, assertion);

        // Parse AuthnStatement
        parseAuthnStatement(assertionElement, assertion);

        // Parse AttributeStatement
        parseAttributeStatement(assertionElement, assertion);

        return assertion;
    }

    /**
     * Parse the Subject element from an Assertion
     */
    private void parseSubject(Element assertionElement, SamlAssertion assertion) throws SamlProcessingException {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() == 0) {
            return;
        }

        Element subjectElement = (Element) subjectNodes.item(0);

        // Parse NameID
        NodeList nameIdNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            assertion.setNameId(nameIdElement.getTextContent().trim());
            assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
        }

        // Parse SubjectConfirmation
        NodeList subjectConfNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmation");
        if (subjectConfNodes.getLength() > 0) {
            Element subjectConfElement = (Element) subjectConfNodes.item(0);
            assertion.setSubjectConfirmationMethod(subjectConfElement.getAttribute("Method"));
        }
    }

    /**
     * Parse the Conditions element from an Assertion
     */
    private void parseConditions(Element assertionElement, SamlAssertion assertion) {
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() == 0) {
            return;
        }

        Element conditionsElement = (Element) conditionsNodes.item(0);

        String notBefore = conditionsElement.getAttribute("NotBefore");
        if (notBefore != null && !notBefore.isEmpty()) {
            assertion.setNotBefore(parseInstant(notBefore));
        }

        String notOnOrAfter = conditionsElement.getAttribute("NotOnOrAfter");
        if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
            assertion.setNotOnOrAfter(parseInstant(notOnOrAfter));
        }

        // Parse AudienceRestriction
        NodeList audienceRestrictionNodes = conditionsElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AudienceRestriction");
        if (audienceRestrictionNodes.getLength() > 0) {
            Element audienceRestrictionElement = (Element) audienceRestrictionNodes.item(0);
            String audience = getChildElementText(audienceRestrictionElement, SAML2_ASSERTION_NS, "Audience");
            assertion.setAudience(audience);
        }
    }

    /**
     * Parse the AuthnStatement element from an Assertion
     */
    private void parseAuthnStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() == 0) {
            return;
        }

        Element authnStatementElement = (Element) authnStatementNodes.item(0);

        String authnInstant = authnStatementElement.getAttribute("AuthnInstant");
        if (authnInstant != null && !authnInstant.isEmpty()) {
            assertion.setAuthnInstant(parseInstant(authnInstant));
        }

        String sessionNotOnOrAfter = authnStatementElement.getAttribute("SessionNotOnOrAfter");
        if (sessionNotOnOrAfter != null && !sessionNotOnOrAfter.isEmpty()) {
            assertion.setSessionNotOnOrAfter(parseInstant(sessionNotOnOrAfter));
        }

        String sessionIndex = authnStatementElement.getAttribute("SessionIndex");
        assertion.setSessionIndex(sessionIndex);

        // Parse AuthnContext
        NodeList authnContextNodes = authnStatementElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnContext");
        if (authnContextNodes.getLength() > 0) {
            Element authnContextElement = (Element) authnContextNodes.item(0);
            String classRef = getChildElementText(authnContextElement, SAML2_ASSERTION_NS, "AuthnContextClassRef");
            assertion.setAuthnContextClassRef(classRef);
        }
    }

    /**
     * Parse the AttributeStatement element from an Assertion
     */
    private void parseAttributeStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList attrStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        if (attrStatementNodes.getLength() == 0) {
            return;
        }

        Element attrStatementElement = (Element) attrStatementNodes.item(0);

        NodeList attributeNodes = attrStatementElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attributeElement = (Element) attributeNodes.item(i);
            String attributeName = attributeElement.getAttribute("Name");

            if (attributeName == null || attributeName.isEmpty()) {
                continue;
            }

            // Get all AttributeValue elements
            NodeList valueNodes = attributeElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
            for (int j = 0; j < valueNodes.getLength(); j++) {
                String value = valueNodes.item(j).getTextContent();
                if (value != null) {
                    assertion.addAttribute(attributeName, value.trim());
                }
            }
        }
    }

    // ========================
