    /**
     * Validate the parsed SAML Response
     */
    private void validateResponse(SamlResponse samlResponse) throws SamlProcessingException {
        // Check response ID exists
        if (samlResponse.getId() == null || samlResponse.getId().isEmpty()) {
            throw new SamlProcessingException("SAML Response is missing required ID attribute");
        }

        // Check status is Success
        if (!samlResponse.isSuccess()) {
            String message = "SAML authentication failed. Status: " + samlResponse.getStatusCode();
            if (samlResponse.getStatusMessage() != null) {
                message += " - " + samlResponse.getStatusMessage();
            }
            throw new SamlProcessingException(message);
        }

        // Check destination
        if (expectedDestination != null && samlResponse.getDestination() != null
                && !samlResponse.getDestination().isEmpty()) {
            if (!expectedDestination.equals(samlResponse.getDestination())) {
                throw new SamlProcessingException(
                        "SAML Response destination mismatch. Expected: " + expectedDestination +
                                ", Actual: " + samlResponse.getDestination());
            }
        }

        // Check response has at least one assertion
        if (samlResponse.getAssertions().isEmpty()) {
            throw new SamlProcessingException("SAML Response does not contain any assertions");
        }

        // Check response age
        if (samlResponse.getIssueInstant() != null && maxResponseAge != null) {
            Instant responseTime = samlResponse.getIssueInstant();
            Instant now = Instant.now();
            if (now.isAfter(responseTime.plus(maxResponseAge).plus(clockSkewTolerance))) {
                throw new SamlProcessingException("SAML Response is too old. IssueInstant: " + responseTime);
            }
        }

        // Validate each assertion
        for (SamlAssertion assertion : samlResponse.getAssertions()) {
            validateAssertion(assertion);
        }
    }

    /**
     * Validate a SAML Assertion
     */
    private void validateAssertion(SamlAssertion assertion) throws SamlProcessingException {
        // Check assertion ID
        if (assertion.getId() == null || assertion.getId().isEmpty()) {
            throw new SamlProcessingException("SAML Assertion is missing required ID attribute");
        }

        // Replay protection: check assertion ID hasn't been used before
        if (usedAssertionIds.contains(assertion.getId())) {
            throw new SamlProcessingException("Replay attack detected: Assertion ID already used: " + assertion.getId());
        }

        // Check NameID exists
        if (assertion.getNameId() == null || assertion.getNameId().isEmpty()) {
            throw new SamlProcessingException("SAML Assertion is missing required NameID in Subject");
        }

        // Check Issuer
        if (assertion.getIssuer() == null || assertion.getIssuer().isEmpty()) {
            throw new SamlProcessingException("SAML Assertion is missing required Issuer element");
        }

        // Validate time conditions
        Instant now = Instant.now();

        if (assertion.getNotBefore() != null) {
            Instant notBefore = assertion.getNotBefore().minus(clockSkewTolerance);
            if (now.isBefore(notBefore)) {
                throw new SamlProcessingException(
                        "SAML Assertion is not yet valid. NotBefore: " + assertion.getNotBefore());
            }
        }

        if (assertion.getNotOnOrAfter() != null) {
            Instant notOnOrAfter = assertion.getNotOnOrAfter().plus(clockSkewTolerance);
            if (now.isAfter(notOnOrAfter)) {
                throw new SamlProcessingException(
                        "SAML Assertion has expired. NotOnOrAfter: " + assertion.getNotOnOrAfter());
            }
        }

        // Validate audience restriction
        if (expectedAudience != null && assertion.getAudience() != null
                && !assertion.getAudience().isEmpty()) {
            if (!expectedAudience.equals(assertion.getAudience())) {
                throw new SamlProcessingException(
                        "SAML Assertion audience mismatch. Expected: " + expectedAudience +
                                ", Actual: " + assertion.getAudience());
            }
        }

        // Mark assertion ID as used (replay protection)
        usedAssertionIds.add(assertion.getId());
    }

