    /**
     * Create an authenticated session from the SAML Response
     */
    private AuthenticatedSession createSessionFromResponse(SamlResponse samlResponse) throws SamlProcessingException {
        // Use the first assertion for session creation
        SamlAssertion assertion = samlResponse.getAssertions().get(0);

        // Generate a unique session ID
        String sessionId = generateSessionId();

        // Create the session
        AuthenticatedSession session = new AuthenticatedSession(
                sessionId,
                assertion.getNameId(),
                assertion.getNameIdFormat(),
                assertion.getAttributes(),
                assertion.getSessionNotOnOrAfter(),
                assertion.getIssuer(),
                assertion.getId(),
                assertion.getAuthnContextClassRef()
        );

        // Store the session
        sessionStore.put(sessionId, session);

        System.out.println("Created authenticated session: " + session);

        return session;
    }

