    /**
     * Get a session by its ID
     */
    public AuthenticatedSession getSession(String sessionId) {
        AuthenticatedSession session = sessionStore.get(sessionId);
        if (session != null) {
            if (session.isExpired() || !session.isActive()) {
                invalidateSession(sessionId);
                return null;
            }
            session.touch();
        }
        return session;
    }

    /**
     * Invalidate a session
     */
    public void invalidateSession(String sessionId) {
        AuthenticatedSession session = sessionStore.remove(sessionId);
        if (session != null) {
            session.invalidate();
            System.out.println("Session invalidated: " + sessionId);
        }
    }

    /**
     * Get all active sessions
     */
    public Collection<AuthenticatedSession> getActiveSessions() {
        List<AuthenticatedSession> activeSessions = new ArrayList<>();
        for (AuthenticatedSession session : sessionStore.values()) {
            if (session.isActive() && !session.isExpired()) {
                activeSessions.add(session);
            }
        }
        return activeSessions;
    }

    /**
     * Clean up expired sessions
     */
    public int cleanupExpiredSessions() {
        int removed = 0;
        Iterator<Map.Entry<String, AuthenticatedSession>> it = sessionStore.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<String, AuthenticatedSession> entry = it.next();
            if (entry.getValue().isExpired() || !entry.getValue().isActive()) {
                entry.getValue().invalidate();
                it.remove();
                removed++;
            }
        }
        if (removed > 0) {
            System.out.println("Cleaned up " + removed + " expired sessions");
        }
        return removed;
    }

    // ========================
    // Utility Methods
    // ========================

    private String getRequiredAttribute(Element element, String attributeName, String elementName)
            throws SamlProcessingException {
        String value = element.getAttribute(attributeName);
        if (value == null || value.isEmpty()) {
            throw new SamlProcessingException(
                    elementName + " element is missing required attribute: " + attributeName);
        }
        return value;
    }

    private String getChildElementText(Element parent, String namespaceUri, String localName) {
        NodeList nodes = parent.getElementsByTagNameNS(namespaceUri, localName);
        if (nodes.getLength() > 0) {
            String text = nodes.item(0).getTextContent();
            return text != null ? text.trim() : null;
        }
        return null;
    }

    private Instant parseInstant(String dateTimeString) {
        try {
            return Instant.parse(dateTimeString);
        } catch (Exception e) {
            System.err.println("Failed to parse datetime: " + dateTimeString);
            return null;
        }
    }

    private String generateSessionId() {
        return UUID.randomUUID().toString();
    }

